// @archeon:file
// @glyph CMP:HomePage
// @intent Landing page — shows app info and platform details
// @chain @v1 NED:system.ready => CMP:HomePage => OUT:ui.ready

// @archeon:section imports
'use client';

import { useState, useEffect } from 'react';
import { platform, arch } from '@tauri-apps/plugin-os';
import { getVersion } from '@tauri-apps/api/app';
// @archeon:endsection

// @archeon:section component
export default function HomePage() {
  const [info, setInfo] = useState({ platform: '', arch: '', version: '' });

  useEffect(() => {
    async function load() {
      const [p, a, v] = await Promise.all([platform(), arch(), getVersion()]);
      setInfo({ platform: p, arch: a, version: v });
    }
    load();
  }, []);

  return (
    <div className="flex flex-col items-center justify-center min-h-screen p-6">
      <h1 className="text-3xl font-bold mb-2">Next.js + Tauri</h1>
      <p className="text-zinc-400 mb-6">
        Edit <code className="text-emerald-400">src/app/page.tsx</code> to get started
      </p>
      <div className="flex gap-4 text-sm text-zinc-500">
        <span>Platform: {info.platform}</span>
        <span>Arch: {info.arch}</span>
        <span>v{info.version}</span>
      </div>
    </div>
  );
}
// @archeon:endsection

