// @archeon:file
// @glyph FNC:TauriCommands
// @intent Typed wrappers around Tauri invoke — single point of contact for all Rust commands
// @chain @v1 NED:system.ready => SHP:nextjs-tauri => OUT:installed

// @archeon:section imports
import { invoke } from '@tauri-apps/api/core';
// @archeon:endsection

// @archeon:section implementation

// --- Filesystem commands ---
export async function readDir(path: string): Promise<string[]> {
  return invoke('read_dir', { path });
}

export async function readTextFile(path: string): Promise<string> {
  return invoke('read_text_file', { path });
}

export async function writeTextFile(path: string, contents: string): Promise<void> {
  return invoke('write_text_file', { path, contents });
}

export async function fileExists(path: string): Promise<boolean> {
  return invoke('file_exists', { path });
}

export async function createDir(path: string): Promise<void> {
  return invoke('create_dir', { path });
}

export async function removeFile(path: string): Promise<void> {
  return invoke('remove_file', { path });
}

export async function removeDir(path: string): Promise<void> {
  return invoke('remove_dir', { path });
}

// --- Shell commands ---
export async function runCommand(program: string, args: string[]): Promise<{ stdout: string; stderr: string; code: number }> {
  return invoke('run_command', { program, args });
}

// --- App info ---
export async function getAppDataDir(): Promise<string> {
  return invoke('get_app_data_dir');
}

export async function getHomeDir(): Promise<string> {
  return invoke('get_home_dir');
}
// @archeon:endsection

