// @archeon:file
// @glyph CMD:TauriMain
// @intent Tauri application entry — registers plugins and commands
// @chain @v1 NED:system.ready => SHP:nextjs-tauri => OUT:installed

// @archeon:section imports
#![cfg_attr(not(debug_assertions), windows_subsystem = "windows")]

mod commands;
// @archeon:endsection

// @archeon:section implementation
fn main() {
    tauri::Builder::default()
        .plugin(tauri_plugin_dialog::init())
        .plugin(tauri_plugin_fs::init())
        .plugin(tauri_plugin_shell::init())
        .plugin(tauri_plugin_os::init())
        .plugin(tauri_plugin_clipboard_manager::init())
        .plugin(tauri_plugin_notification::init())
        .invoke_handler(tauri::generate_handler![
            commands::fs::read_dir,
            commands::fs::read_text_file,
            commands::fs::write_text_file,
            commands::fs::file_exists,
            commands::fs::create_dir,
            commands::fs::remove_file,
            commands::fs::remove_dir,
            commands::shell::run_command,
            commands::app::get_app_data_dir,
            commands::app::get_home_dir,
        ])
        .run(tauri::generate_context!())
        .expect("error while running tauri application");
}
// @archeon:endsection

