// @archeon:file
// @glyph CMD:ShellCommands
// @intent Tauri commands for running shell commands
// @chain @v1 NED:shell => CMD:ShellCommands => OUT:shell.result

// @archeon:section imports
use std::process::Command;
use serde::Serialize;
// @archeon:endsection

// @archeon:section implementation
#[derive(Serialize)]
pub struct CommandOutput {
    pub stdout: String,
    pub stderr: String,
    pub code: i32,
}

#[tauri::command]
pub async fn run_command(program: String, args: Vec<String>) -> Result<CommandOutput, String> {
    let output = Command::new(&program)
        .args(&args)
        .output()
        .map_err(|e| format!("Failed to execute '{}': {}", program, e))?;

    Ok(CommandOutput {
        stdout: String::from_utf8_lossy(&output.stdout).to_string(),
        stderr: String::from_utf8_lossy(&output.stderr).to_string(),
        code: output.status.code().unwrap_or(-1),
    })
}
// @archeon:endsection

